<script setup lang="ts">
import { computed, reactive, ref } from 'vue'
import { onLoad, onPullDownRefresh } from '@dcloudio/uni-app'
import { getMobileWarehouseItemCategories, getMobileWarehouseOverview, receiveMobileWarehouseStock, saveMobileWarehouseItem } from '@/api/business'
import { canPerformMobileAction } from '@/permissions'
import { useSessionStore } from '@/stores'
import type { WarehouseItem, WarehouseItemCategory, WarehouseOverview } from '@/types/business'

const session = useSessionStore()
const itemId = ref(0), warehouseId = ref<string | number>(''), overview = ref<WarehouseOverview | null>(null), categories = ref<WarehouseItemCategory[]>([])
const loading = ref(false), saving = ref(false), message = ref(''), categoryIndex = ref(0)
const form = reactive({ code:'', name:'', imageUrl:'', unit:'', purchaseUnit:'', ingredientUnit:'', unitConversionText:'', spec:'', warehouseLocation:'', unitPrice:'0', shelfLifeDays:'', minStockQuantity:'0', expiryAlertDays:'', itemAttributes:'', itemDescription:'' })
const batch = reactive({ batchNo:'', receivedDate:today(), expiryDate:'', quantity:'', unitCost:'', note:'' })
const item = computed<WarehouseItem | null>(() => overview.value?.items.find(row => row.id === itemId.value) || null)
const canConfigure = computed(() => canPerformMobileAction(session.user, 'warehouse.alert.configure'))
const canPurchase = computed(() => canPerformMobileAction(session.user, 'warehouse.purchase'))
const flatCategories = computed(() => flatten(categories.value))
const selectedCategory = computed(() => flatCategories.value[categoryIndex.value])
const batches = computed(() => (overview.value?.stockBatches || []).filter(row => row.itemId === itemId.value))
const movements = computed(() => (overview.value?.movements || []).filter(row => row.itemId === itemId.value))

onLoad(query => { itemId.value = Number(query?.itemId || 0); warehouseId.value = String(query?.warehouseId || ''); void refresh() })
onPullDownRefresh(async () => { await refresh(); uni.stopPullDownRefresh() })
async function refresh() { if (!itemId.value || !warehouseId.value || loading.value) return; loading.value = true; message.value = ''; try { const [nextOverview,nextCategories] = await Promise.all([getMobileWarehouseOverview(warehouseId.value),getMobileWarehouseItemCategories()]); overview.value=nextOverview; categories.value=nextCategories; fill(nextOverview.items.find(row=>row.id===itemId.value)||null) } catch (e) { message.value=e instanceof Error?e.message:'物料详情加载失败。' } finally { loading.value=false } }
function fill(row:WarehouseItem|null) { if (!row) return; form.code=row.code;form.name=row.name;form.imageUrl=row.imageUrl||'';form.unit=row.stockUnit||row.unit||'';form.purchaseUnit=row.purchaseUnit||'';form.ingredientUnit=row.ingredientUnit||'';form.unitConversionText=row.unitConversionText||'';form.spec=row.spec||'';form.warehouseLocation=row.warehouseLocation||'';form.unitPrice=String(row.unitPrice||0);form.shelfLifeDays=row.shelfLifeDays===undefined?'':String(row.shelfLifeDays);form.minStockQuantity=String(row.minStockQuantity||0);form.expiryAlertDays=row.expiryAlertDays===undefined?'':String(row.expiryAlertDays);form.itemAttributes=row.itemAttributes||'';form.itemDescription=row.itemDescription||'';categoryIndex.value=Math.max(0,flatCategories.value.findIndex(category=>category.id===row.categoryId)) }
async function save() { if (!canConfigure.value || !item.value || !selectedCategory.value || !form.code.trim() || !form.name.trim()) return; saving.value=true;try { await saveMobileWarehouseItem({id:item.value.id,code:form.code.trim(),name:form.name.trim(),categoryId:selectedCategory.value.id,imageUrl:form.imageUrl.trim()||undefined,unit:form.unit.trim()||undefined,stockUnit:form.unit.trim()||undefined,purchaseUnit:form.purchaseUnit.trim()||undefined,ingredientUnit:form.ingredientUnit.trim()||undefined,unitConversionText:form.unitConversionText.trim()||undefined,spec:form.spec.trim()||undefined,warehouseLocation:form.warehouseLocation.trim()||undefined,unitPrice:number(form.unitPrice),shelfLifeDays:optional(form.shelfLifeDays),minStockQuantity:number(form.minStockQuantity),expiryAlertDays:optional(form.expiryAlertDays),alertEnabled:true,itemAttributes:form.itemAttributes.trim()||undefined,itemDescription:form.itemDescription.trim()||undefined,active:item.value.active});message.value='物料档案已保存。';await refresh()} catch(e){message.value=e instanceof Error?e.message:'物料保存失败。'}finally{saving.value=false} }
async function receiveBatch(){if(!canPurchase.value||!item.value||!batch.batchNo.trim()||!batch.receivedDate||number(batch.quantity)<=0||number(batch.unitCost)<0)return; saving.value=true;try{await receiveMobileWarehouseStock({warehouseId:warehouseId.value, itemId:item.value.id,batchNo:batch.batchNo.trim(),receivedDate:batch.receivedDate,expiryDate:batch.expiryDate||undefined,quantity:number(batch.quantity),unitCost:number(batch.unitCost),note:batch.note.trim()||undefined,clientRequestId:`mobile-manual-receipt-${Date.now()}`});batch.batchNo='';batch.expiryDate='';batch.quantity='';batch.unitCost='';batch.note='';message.value='批次已入库。';await refresh()}catch(e){message.value=e instanceof Error?e.message:'批次入库失败。'}finally{saving.value=false}}
function number(value:string){const result=Number(value||0);return Number.isFinite(result)?result:0}function optional(value:string){return value.trim()===''?undefined:number(value)}function today(){return new Date().toISOString().slice(0,10)}function flatten(rows:WarehouseItemCategory[],prefix=''):WarehouseItemCategory[]{return rows.flatMap(row=>[{...row,name:`${prefix}${row.name}`},...flatten(row.children||[],`${prefix}— `)])}
</script>
<template><view class="page"><view v-if="message" class="notice">{{message}}</view><view v-if="!item&&!loading" class="empty">物料不存在或无权访问。</view><template v-if="item"><view class="header"><text class="eyebrow">{{item.code}}</text><text class="title">{{item.name}}</text><text class="copy">可用 {{item.warehouseAvailableQuantity}} {{item.unit||''}} · 最近到期 {{item.nearestExpiryDate||'暂无'}}</text></view><view class="guide"><text class="section">使用说明</text><text class="guide-copy">先查看当前可用库存、仓位和近期到期批次；需要维护物料资料时修改上方字段后保存。</text><text v-if="canPurchase" class="guide-copy">实际到货请在“手工批次入库”填写批次号、到货日期、数量和成本，便于后续追溯。</text></view><view v-if="canConfigure" class="card"><text class="section">物料档案</text><input v-model="form.code" class="input" placeholder="物料编码"/><input v-model="form.name" class="input" placeholder="物料名称"/><picker :range="flatCategories" range-key="name" :value="categoryIndex" @change="categoryIndex=Number($event.detail.value)"><view class="input">类别：{{selectedCategory?.name||'请选择'}}</view></picker><input v-model="form.imageUrl" class="input" placeholder="物料图片地址（选填）"/><input v-model="form.unit" class="input" placeholder="库存单位"/><input v-model="form.purchaseUnit" class="input" placeholder="采购单位"/><input v-model="form.ingredientUnit" class="input" placeholder="配料单位"/><input v-model="form.unitConversionText" class="input" placeholder="单位换算"/><input v-model="form.spec" class="input" placeholder="规格"/><input v-model="form.warehouseLocation" class="input" placeholder="仓位"/><input v-model="form.unitPrice" class="input" type="digit" placeholder="采购单价"/><input v-model="form.shelfLifeDays" class="input" type="number" placeholder="保质期天数"/><input v-model="form.expiryAlertDays" class="input" type="number" placeholder="临期预警天数"/><input v-model="form.minStockQuantity" class="input" type="digit" placeholder="最低库存"/><input v-model="form.itemAttributes" class="input" placeholder="物料属性"/><textarea v-model="form.itemDescription" class="input" placeholder="储存、使用或采购说明"/><button class="primary" :loading="saving" @click="save">保存物料档案</button></view><view v-if="canPurchase" class="card"><text class="section">手工批次入库</text><input v-model="batch.batchNo" class="input" placeholder="批次号"/><picker mode="date" :value="batch.receivedDate" @change="batch.receivedDate=$event.detail.value"><view class="input">到货日期：{{batch.receivedDate}}</view></picker><picker mode="date" :value="batch.expiryDate" @change="batch.expiryDate=$event.detail.value"><view class="input">到期日期：{{batch.expiryDate||'未设置'}}</view></picker><input v-model="batch.quantity" class="input" type="digit" placeholder="入库数量"/><input v-model="batch.unitCost" class="input" type="digit" placeholder="单位成本"/><input v-model="batch.note" class="input" placeholder="入库说明"/><button class="primary" :loading="saving" @click="receiveBatch">确认批次入库</button></view><text class="heading">批次库存</text><view v-for="row in batches" :key="row.id" class="card"><text class="section">{{row.batchNo}}</text><text class="copy">库存 {{row.quantity}} · 入库 {{row.receivedDate}} · 到期 {{row.expiryDate||'未设置'}}</text></view><text class="heading">近期流水</text><view v-for="row in movements" :key="row.id" class="card"><text class="section">{{row.movementTypeLabel}} {{row.quantityDelta>0?'+':''}}{{row.quantityDelta}}</text><text class="copy">{{row.operatorName||'系统'}} · {{row.createdAt||'—'}} · 批次 {{row.batchNo||'—'}}</text></view></template></view></template>
<style scoped lang="scss">.page{min-height:100vh;padding:24rpx;background:#f2f6f5}.header,.card,.guide,.notice,.empty{margin-top:16rpx;padding:24rpx;background:#fff;border:1rpx solid #d9e6e3;border-radius:16rpx}.guide{background:#edf7f5;border-color:#c8e2dc}.eyebrow,.copy,.guide-copy{display:block;color:#71807d;font-size:24rpx}.guide-copy{margin-top:10rpx;line-height:1.55;color:#32635e}.title{display:block;margin-top:6rpx;font-size:38rpx;font-weight:750}.section,.heading{display:block;font-size:29rpx;font-weight:700}.heading{margin:28rpx 2rpx 12rpx}.input{box-sizing:border-box;width:100%;margin-top:12rpx;padding:18rpx;background:#f7faf9;border-radius:12rpx}.primary{margin-top:16rpx;background:#27655f;color:#fff}.notice,.empty{text-align:center;color:#71807d}</style>
